# Bicep: custom role with DataActions
targetScope = 'subscription'

var blobReaderTaggerRoleId = guid('blob-reader-tagger', subscription().id)

resource blobReaderTaggerRole 'Microsoft.Authorization/roleDefinitions@2022-04-01' = {
  name: blobReaderTaggerRoleId
  properties: {
    roleName: 'Blob Reader Tagger'
    description: 'Read blobs and write blob index tags.'
    type: 'CustomRole'
    permissions: [
      {
        actions: [
          'Microsoft.Storage/storageAccounts/blobServices/containers/read'
          'Microsoft.Resources/subscriptions/resourceGroups/read'
        ]
        notActions: []
        dataActions: [
          'Microsoft.Storage/storageAccounts/blobServices/containers/blobs/read'
          'Microsoft.Storage/storageAccounts/blobServices/containers/blobs/tags/write'
          'Microsoft.Storage/storageAccounts/blobServices/containers/blobs/tags/read'
        ]
        notDataActions: []
      }
    ]
    assignableScopes: [ subscription().id ]
  }
}

# Terraform: custom role with DataActions
resource "azurerm_role_definition" "blob_reader_tagger" {
  name  = "Blob Reader Tagger"
  scope = "/subscriptions/${var.subscription_id}"

  permissions {
    actions = [
      "Microsoft.Storage/storageAccounts/blobServices/containers/read",
      "Microsoft.Resources/subscriptions/resourceGroups/read",
    ]
    not_actions = []
    data_actions = [
      "Microsoft.Storage/storageAccounts/blobServices/containers/blobs/read",
      "Microsoft.Storage/storageAccounts/blobServices/containers/blobs/tags/write",
      "Microsoft.Storage/storageAccounts/blobServices/containers/blobs/tags/read",
    ]
    not_data_actions = []
  }

  assignable_scopes = ["/subscriptions/${var.subscription_id}"]
}
